using ExcelDna.Integration;
using System;
using System.Diagnostics;
using System.IO;
using System.Windows.Forms;

namespace RExcelBridge;

public static class PlotCommands
{
    // Default dimensions for test plots created from the menu or RPlotTest().
    // These control the PNG generated by R, not necessarily the final display
    // size in Excel if Excel-side insertion code overrides width/height.
    private const int DefaultTestPlotWidth = 1200;
    private const int DefaultTestPlotHeight = 800;

    private const string TestPlotTag = "TestPlot";
    private const string TestPlotCode = "plot(1:10, 1:10, main='RExcelBridge Test Plot')";

    [ExcelFunction(
        Name = "RPlotTest",
        Description = "Create a simple base R test plot and return the PNG path.",
        Category = "RExcelBridge")]
    public static object RPlotTest()
    {
        try
        {
            return RBridge.Plot(TestPlotCode, TestPlotTag, DefaultTestPlotWidth, DefaultTestPlotHeight);
        }
        catch (Exception ex)
        {
            return $"Error: {ex.Message}";
        }
    }

    [ExcelCommand(
        MenuName = "RExcelBridge",
        MenuText = "Insert Plot From Selected Cell",
        ShortCut = "^+P")]
    public static void InsertPlotFromSelectedCellCommand()
    {
        try
        {
            object result = RBridge.InsertPlotFromSelectedCell();
            string message = result?.ToString() ?? string.Empty;

            if (IsErrorMessage(message))
            {
                MessageBox.Show(message, "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            TrySetStatusBar("RExcelBridge: plot inserted from selected cell.");
        }
        catch (Exception ex)
        {
            MessageBox.Show($"Error: {ex.Message}", "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    [ExcelCommand(
        MenuName = "RExcelBridge",
        MenuText = "Create And Insert Test Plot")]
    public static void CreateAndInsertTestPlotCommand()
    {
        try
        {
            object plotResult = RBridge.Plot(TestPlotCode, TestPlotTag, DefaultTestPlotWidth, DefaultTestPlotHeight);
            string file = plotResult?.ToString() ?? string.Empty;

            if (string.IsNullOrWhiteSpace(file))
            {
                MessageBox.Show("Error: plot path was blank.", "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            if (IsErrorMessage(file))
            {
                MessageBox.Show(file, "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            object insertResult = RBridge.InsertPlotFile(file);
            string insertMessage = insertResult?.ToString() ?? string.Empty;

            if (IsErrorMessage(insertMessage))
            {
                MessageBox.Show(insertMessage, "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            TrySetStatusBar(
                $"RExcelBridge: test plot created and inserted ({DefaultTestPlotWidth}x{DefaultTestPlotHeight}).");
        }
        catch (Exception ex)
        {
            MessageBox.Show($"Error: {ex.Message}", "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    [ExcelCommand(
        MenuName = "RExcelBridge",
        MenuText = "Open Plot Folder")]
    public static void OpenPlotFolderCommand()
    {
        try
        {
            string folder = RBridge.GetPlotDirectory();

            if (string.IsNullOrWhiteSpace(folder))
            {
                MessageBox.Show("Error: plot folder path was blank.", "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
                return;
            }

            Directory.CreateDirectory(folder);

            Process.Start(new ProcessStartInfo
            {
                FileName = "explorer.exe",
                Arguments = $"\"{folder}\"",
                UseShellExecute = true
            });

            TrySetStatusBar("RExcelBridge: opened plot folder.");
        }
        catch (Exception ex)
        {
            MessageBox.Show($"Error: {ex.Message}", "RExcelBridge", MessageBoxButtons.OK, MessageBoxIcon.Error);
        }
    }

    private static bool IsErrorMessage(string message)
    {
        return !string.IsNullOrWhiteSpace(message) &&
               message.StartsWith("Error:", StringComparison.OrdinalIgnoreCase);
    }

    private static void TrySetStatusBar(string message)
    {
        try
        {
            dynamic app = ExcelDnaUtil.Application;
            app.StatusBar = message;
        }
        catch
        {
            // Ignore status bar failures.
        }
    }
}